import{_ as o,H as e,f as a,i as d}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"文法基础","description":"","frontmatter":{},"headers":[],"relativePath":"../interpreterLearning/07-文法基础.md","filePath":"../interpreterLearning/07-文法基础.md","lastUpdated":1778496697000}'),s={name:"../interpreterLearning/07-文法基础.md"};function n(r,t,c,p,i,l){return e(),a("div",null,[...t[0]||(t[0]=[d(`<h1 id="文法基础" tabindex="-1">文法基础 <a class="header-anchor" href="#文法基础" aria-label="Permalink to &quot;文法基础&quot;">​</a></h1><p>词法分析产出的是一串 token,但 <code>if x &gt; 0 { ... }</code> 是不是合法 Mochi 程序?<code>a + b * c</code> 该按 <code>a + (b * c)</code> 还是 <code>(a + b) * c</code> 解析?这些问题词法回答不了——<strong>它们属于文法的世界</strong>。工程师视角下不需要证明文法等价、不需要啃龙书第三章,但有几样东西必须懂:<strong>BNF/EBNF 怎么读、LL 与 LR 的取舍、二义性陷阱、优先级表怎么排</strong>。不懂这些,后面 08 的递归下降和 09 的 Pratt 都是黑盒。</p><blockquote><p>一句话先记住:<strong>文法 = 一组「字符串重写规则」,定义&quot;什么是合法程序&quot;</strong>。<strong>真实语言基本都用 LL(手写递归下降) 或 PEG,LR(yacc/bison) 在式微</strong>——LR 错误信息差、不易扩展、上下文敏感场景跪。</p></blockquote><hr><h2 id="一、文法到底要描述什么" tabindex="-1">一、文法到底要描述什么 <a class="header-anchor" href="#一、文法到底要描述什么" aria-label="Permalink to &quot;一、文法到底要描述什么&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>词法层:  &quot;if&quot; &quot;x&quot; &quot;&gt;&quot; &quot;0&quot; &quot;{&quot; ... &quot;}&quot;    ← 已分成 token</span></span>
<span class="line"><span>文法层:  这串 token 是不是合法的 if 语句?</span></span></code></pre></div><p>文法 = <strong>形式化描述哪些 token 串是合法程序</strong>。形式上写作 <code>G = (N, T, P, S)</code>:N 非终结符(<code>IfStmt</code>、<code>Expr</code> ...)、T 终结符(token)、P 产生式规则、S 起始符号(通常是 <code>Program</code>)。<strong>不用背符号,记产生式怎么读就够</strong>。</p><hr><h2 id="二、bnf-与-ebnf" tabindex="-1">二、BNF 与 EBNF <a class="header-anchor" href="#二、bnf-与-ebnf" aria-label="Permalink to &quot;二、BNF 与 EBNF&quot;">​</a></h2><p><strong>BNF</strong>(Backus-Naur Form)最古老,样子是 <code>&lt;expr&gt; ::= &lt;term&gt; | &lt;expr&gt; &quot;+&quot; &lt;term&gt;</code>——问题:递归丑陋、不支持 <code>* + ?</code> 重复符。</p><p><strong>EBNF</strong>(Extended BNF)加了正则风格元符号,可读多了:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>expr   = term (&quot;+&quot; term)*</span></span>
<span class="line"><span>term   = factor (&quot;*&quot; factor)*</span></span>
<span class="line"><span>factor = number | &quot;(&quot; expr &quot;)&quot;</span></span></code></pre></div><p>读法表:</p><table tabindex="0"><thead><tr><th>写法</th><th>含义</th></tr></thead><tbody><tr><td><code>A B</code></td><td>A 后接 B(连接)</td></tr><tr><td><code>A | B</code></td><td>A 或 B(选择)</td></tr><tr><td><code>A*</code> <code>A+</code> <code>A?</code></td><td>零或多个 / 一或多个 / 可选</td></tr><tr><td><code>( ... )</code></td><td>分组</td></tr></tbody></table><p>业内事实标准——《Crafting Interpreters》《Writing An Interpreter in Go》都用这套。</p><hr><h2 id="三、给-mochi-写一段-ebnf" tabindex="-1">三、给 Mochi 写一段 EBNF <a class="header-anchor" href="#三、给-mochi-写一段-ebnf" aria-label="Permalink to &quot;三、给 Mochi 写一段 EBNF&quot;">​</a></h2><p>只列声明和表达式骨干:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>program  = decl* EOF</span></span>
<span class="line"><span>decl     = letDecl | varDecl | fnDecl | classDecl | stmt</span></span>
<span class="line"><span>letDecl  = &quot;let&quot; IDENT &quot;=&quot; expr</span></span>
<span class="line"><span>fnDecl   = &quot;fn&quot; IDENT &quot;(&quot; params? &quot;)&quot; block</span></span>
<span class="line"><span>stmt     = ifStmt | whileStmt | forStmt | block | exprStmt</span></span>
<span class="line"><span>ifStmt   = &quot;if&quot; expr block (&quot;else&quot; (ifStmt | block))?</span></span>
<span class="line"><span>block    = &quot;{&quot; decl* &quot;}&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>expr     = assign</span></span>
<span class="line"><span>assign   = logicOr (&quot;=&quot; assign)?</span></span>
<span class="line"><span>logicOr  = logicAnd (&quot;||&quot; logicAnd)*</span></span>
<span class="line"><span>logicAnd = equality (&quot;&amp;&amp;&quot; equality)*</span></span>
<span class="line"><span>equality = compare ((&quot;==&quot; | &quot;!=&quot;) compare)*</span></span>
<span class="line"><span>compare  = term  ((&quot;&lt;&quot; | &quot;&gt;&quot; | &quot;&lt;=&quot; | &quot;&gt;=&quot;) term)*</span></span>
<span class="line"><span>term     = factor ((&quot;+&quot; | &quot;-&quot;) factor)*</span></span>
<span class="line"><span>factor   = unary  ((&quot;*&quot; | &quot;/&quot;) unary)*</span></span>
<span class="line"><span>unary    = (&quot;-&quot; | &quot;!&quot;) unary | call</span></span>
<span class="line"><span>call     = primary ( &quot;(&quot; args? &quot;)&quot; | &quot;[&quot; expr &quot;]&quot; | &quot;.&quot; IDENT )*</span></span>
<span class="line"><span>primary  = NUMBER | STRING | IDENT | &quot;(&quot; expr &quot;)&quot; | &quot;true&quot; | &quot;false&quot;</span></span></code></pre></div><p>注意 <code>expr</code> 那 10 层楼梯——<strong>这就是递归下降里最丑的一段</strong>,09 篇用 Pratt 替掉。</p><hr><h2 id="四、ll-vs-lr-自顶向下-vs-自底向上" tabindex="-1">四、LL vs LR:自顶向下 vs 自底向上 <a class="header-anchor" href="#四、ll-vs-lr-自顶向下-vs-自底向上" aria-label="Permalink to &quot;四、LL vs LR:自顶向下 vs 自底向上&quot;">​</a></h2><p>两大历史流派:</p><table tabindex="0"><thead><tr><th>维度</th><th>LL(自顶向下)</th><th>LR(自底向上)</th></tr></thead><tbody><tr><td>思路</td><td>从起始符号开始,<strong>预测</strong>下一步用哪条产生式</td><td>从 token 开始,<strong>移进-归约</strong>,凑出非终结符</td></tr><tr><td>代表</td><td>递归下降、ANTLR、PEG</td><td>yacc、bison、GLR</td></tr><tr><td>表达力</td><td>LL(k) 弱,通常不能左递归</td><td>LR(k) 更强,能左递归</td></tr><tr><td>错误信息</td><td><strong>好</strong>(知道在找什么)</td><td>差(只知道&quot;不能归约&quot;)</td></tr><tr><td>上下文敏感</td><td><strong>容易加 hack</strong></td><td>难</td></tr><tr><td>工业现状</td><td>V8 / CPython / rustc / Go / Swift / TS 全是这条</td><td>仅存于 GCC 老代码、PostgreSQL SQL parser</td></tr></tbody></table><p><strong>结论</strong>:<strong>LR 正在式微</strong>。不是性能问题——是<strong>错误信息和可维护性</strong>:LR 报错只能说&quot;unexpected token&quot;,手写 LL 能说&quot;<code>if</code> 后面少了 <code>{</code>,你是不是漏写了大括号&quot;。<strong>PEG</strong>(Parsing Expression Grammar)是 LL 近亲,加了&quot;有序选择&quot; <code>/</code>,<strong>CPython 3.9+ 从 LL(1) 切到 PEG</strong>——见 <code>Grammar/python.gram</code>。</p><hr><h2 id="五、二义性陷阱" tabindex="-1">五、二义性陷阱 <a class="header-anchor" href="#五、二义性陷阱" aria-label="Permalink to &quot;五、二义性陷阱&quot;">​</a></h2><p>文法写不好会<strong>二义</strong>——同一串 token 有多种解析树。两个经典坑:</p><p><strong>5.1 if-else 悬挂(dangling else)</strong>——<code>if A if B X else Y</code>,<code>else</code> 配哪个 <code>if</code>?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解释 1:  if A { if B X else Y }   ← else 配近的 if</span></span>
<span class="line"><span>解释 2:  if A { if B X } else Y   ← else 配远的 if</span></span></code></pre></div><p>EBNF <code>ifStmt = &quot;if&quot; expr block (&quot;else&quot; ...)?</code> 看不出二义。<strong>所有 C-like 语言都选「else 配最近的 if」</strong>,靠手写解析器的贪心 match 实现。<strong>Mochi 强制 <code>{}</code> 块</strong>,这种二义根本不出现——这就是为什么 Go、Rust、Swift 全强制大括号。</p><p><strong>5.2 优先级二义</strong>——<code>a + b * c</code> 两种树。<code>expr = expr (&quot;+&quot;|&quot;*&quot;) expr</code> 这种&quot;扁平&quot;文法二义。<strong>正确写法</strong>是把优先级编进结构:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>term   = factor ((&quot;+&quot;|&quot;-&quot;) factor)*    ← 低优先级在外层</span></span>
<span class="line"><span>factor = unary  ((&quot;*&quot;|&quot;/&quot;) unary)*     ← 高优先级在内层</span></span></code></pre></div><p><strong>优先级 = 嵌套层级</strong>:越内层越紧地&quot;抱住&quot;操作数。</p><hr><h2 id="六、mochi-运算符优先级与结合性" tabindex="-1">六、Mochi 运算符优先级与结合性 <a class="header-anchor" href="#六、mochi-运算符优先级与结合性" aria-label="Permalink to &quot;六、Mochi 运算符优先级与结合性&quot;">​</a></h2><p>完整表,从低到高:</p><table tabindex="0"><thead><tr><th>级别</th><th>运算符</th><th>结合性</th><th>例子</th></tr></thead><tbody><tr><td>1</td><td><code>=</code></td><td>右</td><td><code>a = b = 1</code> → <code>a = (b = 1)</code></td></tr><tr><td>2</td><td><code>||</code></td><td>左</td><td><code>a || b || c</code> → <code>(a||b) || c</code></td></tr><tr><td>3</td><td><code>&amp;&amp;</code></td><td>左</td><td><code>a &amp;&amp; b &amp;&amp; c</code></td></tr><tr><td>4</td><td><code>== !=</code></td><td>左</td><td><code>a == b != c</code></td></tr><tr><td>5</td><td><code>&lt; &gt; &lt;= &gt;=</code></td><td>左</td><td><code>a &lt; b</code></td></tr><tr><td>6</td><td><code>+ -</code></td><td>左</td><td><code>a - b - c</code> → <code>(a-b) - c</code></td></tr><tr><td>7</td><td><code>* /</code></td><td>左</td><td><code>a * b * c</code></td></tr><tr><td>8</td><td><code>-x !x</code>(一元前缀)</td><td>右</td><td><code>--x</code> → <code>-(-x)</code></td></tr><tr><td>9</td><td><code>f(args)</code> <code>a[i]</code> <code>a.b</code></td><td>左</td><td><code>a.b.c</code> → <code>(a.b).c</code>、<code>f()()</code> 链式调用</td></tr></tbody></table><p><strong>左结合</strong>:<code>a - b - c = (a - b) - c</code>,不是 <code>a - (b - c)</code>(否则 <code>5 - 2 - 1</code> 算出来是 4 而不是 2)。<strong>右结合</strong>:<code>a = b = 1</code>,先算 <code>b = 1</code>(产出值 1),再 <code>a = 1</code>。这张表 09 篇会一对一映射成 Pratt 的 <code>bp(op)</code> 数字——<strong>优先级表就是 Pratt 的输入</strong>。</p><hr><h2 id="七、工业级怎么做" tabindex="-1">七、工业级怎么做 <a class="header-anchor" href="#七、工业级怎么做" aria-label="Permalink to &quot;七、工业级怎么做&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>文件</th><th>方案</th></tr></thead><tbody><tr><td>V8</td><td><code>src/parsing/parser-base.h</code> <code>parser.cc</code></td><td>手写递归下降 + 表达式 Pratt-ish</td></tr><tr><td>CPython 3.9+</td><td><code>Parser/parser.c</code>(由 <code>Grammar/python.gram</code> 经 pegen 生成)</td><td>PEG</td></tr><tr><td>rustc</td><td><code>compiler/rustc_parse/src/parser/</code></td><td>手写递归下降 + 表达式 Pratt</td></tr><tr><td>Go</td><td><code>src/go/parser/parser.go</code></td><td>手写递归下降,全在一个文件</td></tr><tr><td>TypeScript</td><td><code>src/compiler/parser.ts</code></td><td>手写递归下降,单文件 9000+ 行</td></tr><tr><td>GCC C(老)</td><td>bison 生成</td><td><strong>GCC 4.1+ 已改手写</strong>(<code>gcc/c/c-parser.cc</code>)</td></tr></tbody></table><p><strong>注意 CPython 这条</strong>——切到 PEG 后,<strong>Python 才支持带括号的多行 <code>with</code></strong>,旧 LL(1) 表达力够不上。</p><hr><h2 id="八、mochi-这里偷懒了" tabindex="-1">八、Mochi 这里偷懒了 <a class="header-anchor" href="#八、mochi-这里偷懒了" aria-label="Permalink to &quot;八、Mochi 这里偷懒了&quot;">​</a></h2><ul><li><strong>不写完整文法</strong>:正式语言要把字符串转义、模板字符串、嵌套注释全编进 EBNF——Mochi 文档只列骨干,细节藏在解析器代码注释里</li><li><strong>不证明无二义性</strong>:Mochi 文法是 LL(2),靠强制大括号 + 手写贪心 match 回避二义,不做形式证明</li><li><strong>不上 PEG 生成器</strong>:工业级 PEG(像 pegen)能省一半代码,但调试栈太深、错误信息差——Mochi 全程手写</li><li><strong>不维护&quot;期待集&quot;</strong>:rustc 报错能列&quot;expected one of <code>let</code>, <code>if</code>, ...&quot;——需要在 parser 状态里维护 first set,Mochi 只报单 token 期待</li></ul><hr><p>下一篇:<code>08-递归下降解析器.md</code>,讲清楚怎么把上面这套 EBNF 直接翻译成 60-90 行 TypeScript——<strong>一条产生式一个函数</strong>,外加 panic mode 错误恢复。</p>`,48)])])}const q=o(s,[["render",n]]);export{h as __pageData,q as default};
